  return (
    <div className={`h-screen flex overflow-hidden justify-center items-center ${darkMode ? "bg-[#0a0f27] text-white" : "bg-[#dde3f6]"}`}>
      <div className={`h-[85%] w-[80%] flex bg-opacity-10 bg-white rounded-2xl ${darkMode ? "text-white" : ""}`}>
      <div className={`w-[30%] flex flex-col h-full overflow-scroll scrollbar-hide rounded-l-2xl border-2 border-black ${darkMode ? "text-white" : ""}`}>
        <div className={`h-[65px] flex justify-center items-center sticky top-0 shadow-md ${darkMode ? " bg-opacity-90 text-white" : ""}`}></div>
      </div>
        <div className={`w-[70%] h-full overflow-scroll scrollbar-hide rounded-r-2xl border-2 border-black ${darkMode ? "bg-opacity-90 text-white" : ""}`}>
           <div className={`h-[65px] flex justify-center items-center sticky top-0 shadow-md w-full ${darkMode ? "bg-opacity-90 text-white" : ""}`}></div>
        </div>
        </div>
    </div>
  );
};

export default Chat;
